SELECT cb.player_id, cb.booking_date, cb.court_number
FROM court_bookings cb
WHERE strftime('%Y-%m', cb.booking_date) = strftime('%Y-%m', date('now', '+1 month'));

SELECT "club_id", AVG("duration") AS avg_duration
FROM "court_bookings"
GROUP BY "club_id";

SELECT COUNT(*)
FROM player_weather_matches
WHERE play_recommendation = 1 AND actual_played = 0;

SELECT player_id
FROM court_bookings
WHERE booking_date = '2023-05-01';

SELECT player_id
FROM player_weather_matches
WHERE play_recommendation = 1;

SELECT COUNT(DISTINCT condition_id) AS UniquePlayersWhoPlayed
FROM play_decisions
WHERE play_tennis = 1;

SELECT preferred_time
FROM player_preferences
WHERE player_id = 1;

SELECT COUNT(*)
FROM player_preferences
WHERE temperature_tolerance = 'Cool';

SELECT COUNT(booking_id) AS total_bookings
FROM court_bookings
WHERE club_id = 0;
